var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인은 어렸을 적부터 사부님에게 거두어져 암살훈련을 받으며 자랐소.","JPN":"自分は幼いころ、師匠に引取られ、暗殺訓練を受けながら育ちました。","ENG":"I was taken under my master's wing as a child and was raised as an assassin.","TWN":"在下從小就被師父收留，接受刺客訓練長大。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그리고 오랫동안 흑동이라는 음지의 조직에 몸담아 왔다오.","JPN":"そして、長くにわたり黒東という闇の組織に所属していました。","ENG":"For all this time, I have dwelt within a shadow organization called Black East.","TWN":"並且長期為一個名為黑東的組織效力。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"시엘 양? 잠시만…","JPN":"シエルさん？　ちょっと……","ENG":"Ciel? Hold that thought...","TWN":"希爾同學？你先等一下…"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"지금 하는 얘긴 학생부 기록에 적혀 있지 않은 내용인 것 같은데?","JPN":"今の話は、指導要録に書いてない内容だと思うけど。","ENG":"What you just told me, it's not written anywhere in your school records.","TWN":"你現在說的內容，好像都不在學生資料紀錄表上？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그렇소. 암살자는 목표의 꼬리를 밟되 꼬리를 밟혀선 안 되니까.","JPN":"然様でございます。暗殺者たるもの、標的の尻尾は掴むものであり、掴まれてはなりません。","ENG":"As things should be. An assassin may chase after her target, but should not be caught by one.","TWN":"正是，身為刺客，必須深藏不露，不能讓人逮到把柄。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"이름과 생김새와 행적… 그 무엇도 대외적으로 기록에 남겨선 안된다오.","JPN":"名前と容貌そして活動の痕跡……何一つ外部の記録に残してはいけないのです。","ENG":"One's name, appearance, and behavior... None should be recorded on any material.","TWN":"無論是名字、長相和行蹤…都不能對外留下任何紀錄。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"저기… 지금이 무슨 시간인지 알고 있는 거지?","JPN":"あの……今私たち何をしているのかわかってるよね？","ENG":"Um... You do know what this is, right?","TWN":"同學…你知道現在是什麼時間嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"개인면담은 절대비밀을 보장하며, 선생과 학생이 진솔한 대화를 나누는 시간이라 배웠소.","JPN":"個人面談とは厳格な秘密保持を有し、教師と生徒が率直な対話を交わす時間と教わっています。","ENG":"I learned that personal counseling is time spent between a teacher and student that is confidential and used for open communication.","TWN":"據在下所知，個人諮商是老師與學生一對一的談話時間，而且所有對話內容都不得洩漏出去。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그리고 선생은 학생인 나에게 과거를 물어보았으니 응당 거짓을 말할 수는 없는 것이지.","JPN":"そして自分の過去について質問された以上、無論嘘をつくわけにはいきません。","ENG":"Since you, the teacher, inquired about my past, I am obligated as a student to tell the truth and not to lie.","TWN":"因此在下作為一名學生，當老師問起在下的過去時，當然必須據實以告。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"아니, 그렇긴 한데… 이런 자리에서 갑자기 그런 엄청난 얘길 듣게 될 줄은 몰랐거든.","JPN":"いや、それはそうだけど……ここでいきなりそんなすごい話を聞かされるとは思ってなかったのよね。","ENG":"Yes, that's true, but... I didn't expect to hear something so serious.","TWN":"話是沒錯…但我沒有預料到會聽到這麼震驚的內容。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"어쩔 수 없구려. 비밀을 지키지 못하겠다면 이 자리에서 제거를…","JPN":"仕方ありません。秘密を守れないというなら、この場で抹殺を……","ENG":"Then you leave me no choice. If you cannot keep my secret, then I will have to put an end to you...","TWN":"若是老師無法保守秘密，那在下不得已只好將老師除之…"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"비밀은 지키겠습니다! 무덤까지 가져갈게요! 저주를 받아 무덤에서 좀비로 소생해도 입단속 할게요!","JPN":"秘密は守ります！　お墓まで持っていきます！　もしお墓からゾンビになって蘇っても、口には絶対出しません！","ENG":"I'll keep your secret! I'll take it to my grave! I won't tell a soul, even if I resurrect from the dead and become a zombie!","TWN":"我絕不會說出去！我會把這個秘密帶到墳墓裡！就算因此受到詛咒變成殭屍，我也會把嘴巴管好！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…농담이오.","JPN":"……冗談です。","ENG":"...It was a joke.","TWN":"…在下說笑的。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"아뇨! 분명 엄청난 눈빛으로 노려봤는데요? 저 온몸에 소름이 돋았는데요?","JPN":"いやっ！　確かにものすごい眼差しで睨まれたんですけど？　全身鳥肌立ちましたけど？","ENG":"I don't think so! You were glaring at me! I had chills run down my spine!","TWN":"才不是！你剛才的眼神超認真欸！害我整個起雞皮疙瘩。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그야, 선생의 놀라는 표정을 자세히 보고 싶었거든.","JPN":"それは、先生の驚いた顔をよく見たかったので。","ENG":"That is because I wished for a better look at your astounded expression.","TWN":"那是因為在下想看清楚老師嚇到的樣子。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"너, 눈이 나쁘면 안경을 쓰라고…! 그렇게 눈살 찌푸리면 무섭다니까!","JPN":"目が悪いなら眼鏡をかけなさい……！　あなた、そうやって眉をひそめると怖いのよ！","ENG":"Y-you should wear glasses if you have bad eyesight...! You look so scary when you squint your eyes like that!","TWN":"你視力不好就去配眼鏡…！眼睛睜那麼大是想嚇死誰！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인은 암살자이자 카운터요. 안경처럼 깨지기 쉬운 물건에 의존할 수는 없다네.","JPN":"自分は暗殺者であり、カウンターです。眼鏡のような割れやすいものに頼るわけにはいかないので。","ENG":"I am an assassin and a Counter. I cannot rely on something that can be so easily broken.","TWN":"在下是刺客也是制裁者，不能倚賴像眼鏡那種易碎物。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"어, 어쨌든 암살은 안 돼. 아무리 집안에서 그런 걸 가르쳤다고 해도 말이야. 감옥에 가고 말 거라고?","JPN":"と、とにかく暗殺なんてダメよ。いくら家門でそんなことを教わったとしてもね。刑務所行きになるわよ。","ENG":"A-anyway, no more assassinating, okay? Even if that's what your household has taught you. You're going to end up in prison!","TWN":"總之，當刺客是不好的！就算從小家裡是這麼教你的也不行！你是想去坐牢嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"걱정마오. 법망에 닿지 않는 선에서 은밀하게 처리하고 있으니.","JPN":"ご心配いりません。法には触れぬよう隠密に処理していますので。","ENG":"Fret not. I always handle my work secretly, outside the reach of the common law.","TWN":"請放心，在下會遊走在法律邊緣，低調處理。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"아니… 그런 문제가 아니라, 그런 난폭한 환경에 무방비하게 노출된 시엘 양이 신경 쓰이는 거라고.","JPN":"いや……そういうことじゃなくて、命の危険にさらされるような環境にいるシエルさんのことが心配なの。","ENG":"I mean... that's not what I'm talking about. Ciel, I'm simply concerned about your exposure to such a violent environment.","TWN":"同學…這不是重點，而是你待在那種暴力的環境中並不好。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"이해하오. 자신이 약자라 판단한 대상을 충동적으로 감싸주고 보호하는 건 지극히 본능적인 행동이지.","JPN":"お言葉はわかります。弱い者を衝動的に庇い、保護することはごく本能的な行動です。","ENG":"I understand. It is only natural to have an impulsive urge to protect those that one deems weak.","TWN":"在下明白，人都有保護弱小的天性，"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"하지만 우리 흑동이 행하는 암살은 사사로운 목적으로 행하는 범죄가 아니라오.","JPN":"ですが、我々黒東が行う暗殺は私情で行われる犯罪ではございません。","ENG":"But assassinations carried out by Black East are not crimes committed for selfish reasons.","TWN":"但我們黑東並非為私人的目的而犯罪，"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"내 고향 화천은 백서와 흑동이 통치하기 전까진, 수백 개의 크고 작은 세력이 끊임없이 싸우던 무법도시였지.","JPN":"自分の故郷である華天は、白西と黒東が治めるまでは大小数百の勢力が耐えず争っていた無法地帯でした。","ENG":"Before my hometown, Huatian, was governed by White West and Black East, it was a lawless city with hundreds of factions at war with each other.","TWN":"在下的老家華天，在由白西和黑東統治前，有許多大大小小的勢力，他們成天打打殺殺，目無法紀。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"백서는 정치와 경제로 질서를 잡고 민심을 다스리고, 흑동은 그 뒤에서 암약을 꾸미는 이들을 처리하여 불화의 싹을 거둔다오.","JPN":"白西は政治と経済で秩序を維持しながら民心を治め、黒東はその裏で暗躍を企む者たちを処理し不和の種を除去しているのです。","ENG":"White West brought order to the people through politics and economy. Black West hid in the shadows, removing all seeds of discord.","TWN":"白西從政治和經濟層面來建立秩序，管理民眾，黑東則是在背後處理私下結黨的分子，將那些企圖擾亂社會秩序的人斬草除根。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"두 문파는 그러한 방식으로 치외법권이나 다름없던 도시를 오랫동안 지켜왔소.","JPN":"そうすることによって治外法権も同然であった都市を両門派は守り続けてきました。","ENG":"The two sects have long since maintained this lawless city using such methods.","TWN":"二個門派就是用這樣的方式，長久以來管理如同至外法權的地方。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"그런 일은 다른 어른들에게 맡기면 되잖아. 시엘이 맡는 게 아니라…!","JPN":"そんなことは、大人たちに任せればいいじゃない。シエルさんが引き受けるんじゃなくて……！","ENG":"You should just leave it to the adults and not handle it yourself...!","TWN":"這種事交給大人去做就好，不需要你…！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인은 선생이 걱정하는 것처럼 방황하는 청소년이 아니라오.","JPN":"自分は先生が心配なさっているような放浪の若者ではございません。","ENG":"I am not a wandering youth, as you presume I am.","TWN":"在下並非如老師所擔心，是那種懵懂無知的青少年。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"거두어 준 은인에게 보답하고자, 맡은 일에 충실하고 있었을 뿐이지.","JPN":"自分を育ててくれた恩人に報いるため、任務に忠実であるだけです。","ENG":"I was merely doing my part in serving my master, someone for whom I am grateful for taking me under his wing.","TWN":"在下只是想報答收留我的恩人，盡全力完成所交付於在下的事。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"그럼… 그 은인이 널 죽을 위기에 내몬다고 해도 망설이지 않을 셈이야?","JPN":"じゃあ……もしその恩人があなたを命の危機に追い込んでも、迷いはないってわけ？","ENG":"Then... you won't even hesitate if he sends you on a suicide mission?","TWN":"所以…如果你所謂的恩人要你去死，你也會毫不猶豫地去死嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"물론이오.","JPN":"無論です。","ENG":"No, I will not.","TWN":"那是當然。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"다만, 본인에게 그런 명령을 내릴 사부님은 이제 살아 계시지 않소.","JPN":"ただ、自分にそのような命令を下す師匠は、すでに常世の国へと旅立たれました。","ENG":"However, there is no longer a master who can give me such an order.","TWN":"但，可以對在下說那種話的師父已經不在人世。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"돌아… 가셨구나. 유감이네.","JPN":"お亡くなりに……なったんだね。ごめん。","ENG":"Oh... He passed away. My condolences.","TWN":"你師父…不在啦，我很遺憾。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"그럼! 시엘 양은 이제 조직을 떠나서 다른 삶을 살기 위해 아카데미에 입학한 거지?!","JPN":"そういうことなら！　シエルさんはもう組織から出て、別の人生を生きるためにアカデミーに入学したんだよね！？","ENG":"Okay! Then you must've come to the Academy to leave your old life as an assassin behind and start anew, right, Ciel?!","TWN":"這麼說來！你是脫離組織後，因為想要尋求新的人生，所以才來會來學院就學囉？！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"아니. 본인이 원래 이곳에 온 목적은…","JPN":"いいえ。自分がこの場所を訪ねた目的は……","ENG":"No. My purpose in coming here is...","TWN":"非也，在下來此的目的是…"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"학생회장, 옌 싱 란체스터를 본인의 반려로 삼는 것이오.","JPN":"生徒会長、イェン・シング・ランチェスターを自分の伴侶にすることです。","ENG":"to make the Student President, Yen Xing Lanchester, my partner in life.","TWN":"要讓學生會長嫣杏·蘭賈斯特，成為在下的伴侶。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L49_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"응?","JPN":"えっ？","ENG":"Huh?","TWN":"蛤？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};